+    }
+  }
+}
+`)
+	if err := os.WriteFile(cfgPath, data, 0o644); err != nil {
+		t.Fatalf("write config: %v", err)
+	}
+
+	var out bytes.Buffer
+	var errOut bytes.Buffer
+	code := Run(context.Background(), []string{"--config", cfgPath, "spotify", "logout"}, &out, &errOut)
+	if code != 0 {
