+	}
+
+	after, err := os.ReadFile(cfgPath)
+	if err != nil {
+		t.Fatalf("read config: %v", err)
+	}
+	if strings.Contains(string(after), "access_token") {
+		t.Fatalf("config still contains access_token: %s", string(after))
+	}
+}
